import base64, tarfile, io
from pathlib import Path
ROOT = Path("/content/drive/MyDrive/diploma_plan_sql")
B64 = """

"""
import time
t0 = time.time()
buf = io.BytesIO(base64.b64decode(B64.replace(chr(10),"")))
with tarfile.open(fileobj=buf, mode="r:gz") as tar:
    tar.extractall(ROOT)
nout = len(list((ROOT/"outputs/predictions").iterdir())) if (ROOT/"outputs/predictions").exists() else 0
nrepo = len(list((ROOT/"repo/src/evaluation").iterdir())) if (ROOT/"repo/src/evaluation").exists() else 0
print(f"EXTRACTED in {time.time()-t0:.1f}s; outputs/predictions={nout} entries; repo/src/evaluation={nrepo} entries")
